+        let mut heap2 = FibonacciHeap::new();
+        for &v in &vals {
+            heap1.insert(v, v);
+            heap2.insert(v, v);
+        }
+
+        // into_sorted on one
+        let from_into_sorted = heap1.into_sorted();
+
+        // sequential extract_min on the other
+        let mut from_extract = Vec::new();
+        while let Some(pair) = heap2.extract_min() {
+            from_extract.push(pair);
